# pip install openai
from openai import OpenAI

client = OpenAI()   # reads OPENAI_API_KEY from environment

response = client.chat.completions.create(
    model="gpt-4o",
    messages=[
        {
            "role": "user",
            "content": [
                {
                    "type": "text",
                    "text": "What Python error is shown in this screenshot? "
                             "Give the exact exception type and message, then "
                             "suggest a one-line fix.",
                },
                {
                    "type": "image_url",
                    "image_url": {
                        "url": "https://upload.wikimedia.org/wikipedia/commons/"
                                "thumb/3/3f/Python3.3.0_interpretor.jpg/"
                                "320px-Python3.3.0_interpretor.jpg",
                        "detail": "high",   # "low" reduces token cost at the
                                               # expense of resolution
                    },
                },
            ],
        }
    ],
    max_tokens=300,
)
print(response.choices[0].message.content)
